scwin.sCurrDate;
scwin.cmd;
scwin.loginInfo;
scwin.onpageload = async function () {
  const codeOptions = [{
    grpCd: "OP276",
    compID: "acb_hveqWrkImpleClsCd,gr_results:hveqWrkImpleClsCd"
  }, {
    grpCd: "OP182",
    compID: "gr_results:pchsAdjmStdCd"
  }];
  await $c.data.setCommonCode($p, codeOptions);
  scwin.sCurrDate = $c.date.getServerDateTime($p, "yyyyMMdd");
  scwin.cmd = "";
  scwin.loginInfo = $c.data.getMemInfo($p);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
  $p.setTimeout(function () {
    acb_hveqWrkImpleClsCd.addItem("전체", "", "", 0);
    acb_hveqWrkImpleClsCd.setValue("");
    $c.sbm.execute($p, sbm_lobran);
    ica_stDt.setValue(scwin.sCurrDate);
    ica_endDt.setValue(scwin.sCurrDate);
    acb_lobran.focus();

    // $p.setTimeout(function() {
    //     ica_stDt.setValue("20121201");
    //     ica_endDt.setValue("20121231");
    //     acb_lobran.setValue("6AA");

    // }, {"delay":100});
  }, {
    "delay": 100
  });
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  var res = await $c.gus.cfValidate($p, ica_stDt);
  if (!res) {
    return;
  }
  res = await $c.gus.cfValidate($p, ica_endDt);
  if (!res) {
    return;
  }
  if (ica_stDt.getValue() != "" && ica_endDt.getValue() != "") {
    res = await $c.gus.cfIsAfterDate($p, ica_stDt.getValue(), ica_endDt.getValue(), false);
    if (!res) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
      ica_stDt.focus();
      return;
    }
  }
  ds_results.removeAll();
  ds_search.set("lobranCd", acb_lobran.getValue());
  ds_search.set("hveqWrkImpleClsCd", acb_hveqWrkImpleClsCd.getValue());
  ds_search.set("stDt", ica_stDt.getValue());
  ds_search.set("endDt", ica_endDt.getValue());
  ds_search.set("hveqCd", ds_hidden.get("hid_txt_hveqCd"));
  ds_search.set("wrkImpleNo", ed_wrkImpleNo.getValue());
  ds_search.set("rentCoNo", ed_rentCoNo.getValue());

  // ds_search.UseChangeInfo = false;
  $c.sbm.execute($p, sbm_search);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!(await $c.gus.cfCanOpenPopup($p, inObj, pairObj))) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList; // 공통POP-UP -> 요청화면 

  switch (disGubun) {
    case 1:
      var arrParam = new Array();
      pCode = ed_hveqCd.getValue();
      pName = ed_hveqNm.getValue(); //ds_results.NameValue(ds_results.RowPosition, "vehclNo");

      arrParam[0] = acb_lobran.getValue(); // assgnLobranCd점소코드
      arrParam[1] = ""; // eqKndCd중기종류
      arrParam[2] = ""; // clntCd거래처코드
      arrParam[3] = scwin.sCurrDate; // usblDt작업계획일지
      arrParam[4] = pCode; // eqNo
      arrParam[5] = pName; // 차량번호
      arrParam[6] = pClose; // T,F구분
      arrParam[7] = 'T'; // T,F구분

      let win_url = "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml";
      let opts = {
        id: "hveqPop",
        popupName: "중기조회",
        modal: true,
        type: "browserPopup",
        width: 1156,
        height: 554,
        title: "중기조회"
      };
      rtnList = await $c.win.openPopup($p, win_url, opts, arrParam);
      if (rtnList != null) {
        ed_hveqCd.setValue(rtnList[0]); //단축코드
        ed_hveqNm.setValue(rtnList[1]); //차량FULL코드
        ds_hidden.set("hid_txt_hveqCd", rtnList[12]); //중기코드  
      } else {
        ed_hveqCd.setValue(""); //단축코드
        ed_hveqNm.setValue(""); //차량FULL코드
        ds_hidden.set("hid_txt_hveqCd", ""); //중기코드  
      }
      break;
    case 2:
      pCode = ed_wrkImpleNo.getValue();
      pName = ed_wrkImpleNm.getValue();
      var paramList = scwin.sCurrDate + ",,,,," + acb_lobran.getValue();
      udc_wrkImple.setSelectId("retrieveWrkImple");
      udc_wrkImple.cfCommonPopUp(scwin.udc_wrkImple_callBackFunc, pCode, pName, pClose, null, null, null, null, paramList, 1130, 500, null, null);
      //      작업도구
      //     /*작업도구번호*/    0
      //     /*작업도구명*/   1
      //     /*작업도구종류명*/  2
      //     /*작업도구규격명*/ 3
      //     /*소속부서명*/    4
      //     /*소유구분명*/  5
      //     /*임차기간*/   6
      //     /*거래처명*/ 7
      //     /*물류점소코드 (H)*/ 8
      //     /*작업도구종류코드 (H)*/  9
      //     /*작업도구규격코드 (H)*/  10                     
      //     /*소속부서코드 (H)*/  11
      //     /*소유구분코드 (H)*/ 12
      //     /*거래처코드 (H)*/   13
      break;
    case 3:
      pCode = ed_rentCoNo.getValue().replace(/\s*$/, '');
      pName = ed_rentCoNm.getValue();
      udc_rentCo.setSelectId("retrieveClntList");
      udc_rentCo.cfCommonPopUp(scwin.udc_rentCo_callBackFunc, pCode, pName, pClose, null, null, null, null, ",S", 960, 500, null, null, null, pAllSearch); // 중기협력업체
      break;
    default:
      break;
  }
};

