// Validation
//------------------------------------------------------------------------- 
scwin.f_Validation = async function () {
  var validate = await $c.gus.cfValidate($p, [gr_results]);
  if (!validate) {
    return false;
  }
  for (var i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "pchsAdjmStdCd") == "H") {
      //시간당
      if (ds_results.getCellData(i, "sellAdptHhCnt") == "" || ds_results.getCellData(i, "sellAdptHhCnt") == "0") {
        await $c.win.alert($p, i + 1 + "번째줄의 적용시간을 입력하십시오.");
        // ds_results.getRowPosition() = i;
        // ds_results.ColSelect = "true";		
        // gr_results.Focus();
        // gr_results.SetColumn("sellAdptHhCnt");
        gr_results.setFocusedCell(i, "sellAdptHhCnt", true);
        return false;
      }
    } else {
      if (ds_results.getCellData(i, "sellAdptWt") == "" || ds_results.getCellData(i, "sellAdptWt") == "0") {
        await $c.win.alert($p, i + 1 + "번째줄의 적용중량을 입력하십시오.");
        // ds_results.getRowPosition() = i;
        // ds_results.ColSelect = "true";		
        // gr_results.Focus();
        // gr_results.SetColumn("sellAdptWt");
        gr_results.setFocusedCell(i, "sellAdptWt", true);
        return false;
      }
    }
    if (ds_results.getCellData(i, "calBtn") == "") {
      await $c.win.alert($p, i + 1 + "번째줄의 임대금액을 계산하십시오.");
      return false;
    }
    if (ds_results.getCellData(i, "sellAmt") == 0 && ds_results.getCellData(i, "ctrlSellAmt") == 0) {
      await $c.win.alert($p, i + 1 + "번째줄의 조정금액을 입력하십시오.");
      // ds_results.getRowPosition() = i;
      // ds_results.ColSelect = "true";		
      // gr_results.Focus();
      // gr_results.SetColumn("ctrlSellAmt");
      gr_results.setFocusedCell(i, "ctrlSellAmt", true);
      return false;
    }
  }
  var checkVacationDate = await scwin.f_checkVacationDate();
  if (!checkVacationDate) {
    return false;
  }
  return true;
};

