// 작업시간 Validation
//-------------------------------------------------------------------------  

scwin.f_checkVacationDate = async function () {
  var wrkDt = "";
  var wrkStDt;
  var wrkStHh;
  var wrkStMm;
  var wrkEndDt;
  var wrkEndHh;
  var wrkEndMm;
  var wrkStDtm;
  var wrkEndDtm;
  for (var i = 0; i < ds_results.getRowCount(); i++) {
    wrkDt = ds_results.getCellData(i, "rentDt");
    wrkStDt = ds_results.getCellData(i, "stDt");
    wrkStHh = ds_results.getCellData(i, "stHh");
    wrkStMm = ds_results.getCellData(i, "stHh").substring(2, 4);
    wrkEndDt = ds_results.getCellData(i, "endDt");
    wrkEndHh = ds_results.getCellData(i, "endHh");
    wrkEndMm = ds_results.getCellData(i, "endHh").substring(2, 4);
    wrkStDtm = wrkStDt + wrkStHh;
    wrkEndDtm = wrkEndDt + wrkEndHh;
    if (wrkStMm != "00" && wrkStMm != "30") {
      await $c.win.alert($p, i + 1 + "번째의 시간은 30분 단위로 입력 가능합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.Focus();
      // gr_results.SetColumn("stHh");
      gr_results.setFocusedCell(i, "stHh", true);
      return false;
    }
    if (wrkEndMm != "00" && wrkEndMm != "30") {
      await $c.win.alert($p, i + 1 + "번째의 시간은 30분 단위로 입력 가능합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.Focus();
      // gr_results.SetColumn("endHh");
      gr_results.setFocusedCell(i, "endHh", true);
      return false;
    }

    //작업시작일자가 작업종료일자 이후 인가
    if (wrkStDt > wrkEndDt) {
      //cfAlertMsg(MSG_CM_ERR_039);
      await $c.win.alert($p, i + 1 + "번째의 작업시작일시는 작업종료일시 이전이어야 합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.Focus();
      // gr_results.SetColumn("stDt");
      gr_results.setFocusedCell(i, "stDt", true);
      return false;
    }
    if (wrkStDtm > wrkEndDtm) {
      //cfAlertMsg(MSG_CM_ERR_039);
      await $c.win.alert($p, i + 1 + "번째의 작업시작일시는 작업종료일시 이전이어야 합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.Focus();
      // gr_results.SetColumn("stHh");
      gr_results.setFocusedCell(i, "stHh", true);
      return false;
    }

    //입력한 작업시작일자가 조회일자이후인가
    if (wrkDt > wrkStDt) {
      await $c.win.alert($p, i + 1 + "번째의 근무시간 일자는 기준일자 + 1일까지 입력가능합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.Focus();
      // gr_results.SetColumn("stDt");
      gr_results.setFocusedCell(i, "stDt", true);
      return false;
    }

    //입력한 작업시작일자가 하루를 초과하는가
    var diffDay = await $c.date.diffDate($p, wrkDt, wrkStDt);
    if (diffDay > 1) {
      await $c.win.alert($p, i + 1 + "번째의 근무시간 일자는 기준일자 + 1일까지 입력가능합니다.");
      // gr_results.SetScrolling(i, 1); 
      // gr_results.ColSelect = "true";
      // gr_results.focus();
      // gr_results.SetColumn("stDt");
      gr_results.setFocusedCell(i, "stDt", true);
      return false;
    }
  }
  return true;
};

//-------------------------------------------------------------------------
// 작업시간계산
//-------------------------------------------------------------------------  
scwin.f_diffHour = async function (stDt, stHh, endDt, endHh) {
  var diffDay = await $c.date.diffDate($p, stDt, endDt);
  var dtConverterHour = eval(diffDay) * 24;
  var stHhConverterHour = eval(stHh.substring(0, 2));
  var endHhConverterHour = eval(endHh.substring(0, 2));
  var diffHour;
  var mealTimeCnt = 0; // 중식시간 : 1200~1300, 석식시간 : 1800~1900,야식시간 : 0000~0100 

  if (stHh.substring(2, 4) == 30) {
    stHhConverterHour = stHhConverterHour + 1;
  }
  if (endHh.substring(2, 4) == 30) {
    endHhConverterHour = endHhConverterHour + 1;
  }
  diffHour = dtConverterHour + endHhConverterHour - stHhConverterHour;
  diffDay = eval(diffDay);
  endHhConverterHour = endHhConverterHour + dtConverterHour;
  for (var i = 0; i <= diffDay; i++) {
    if (i > 0) {
      stHhConverterHour = 0;
      endHhConverterHour = endHhConverterHour - 24;
    }
    if (stHhConverterHour <= 12 && endHhConverterHour >= 13) mealTimeCnt++;
    if (stHhConverterHour <= 18 && endHhConverterHour >= 19) mealTimeCnt++;
    if (stHhConverterHour <= 0 && endHhConverterHour >= 1) mealTimeCnt++;
  }
  diffHour = diffHour - mealTimeCnt;
  return diffHour;

  // if( stHhConverterHour <= 12 && dtConverterHour+endHhConverterHour >=13 )mealTimeCnt++;
  // if( stHhConverterHour<= 18 && dtConverterHour+endHhConverterHour >=19 ) mealTimeCnt++;
  // if( stDt != endDt && stHhConverterHour<=0  &&  endHhConverterHour>=1 )mealTimeCnt++;
  // if( stDt != endDt && stHhConverterHour <= 12 && endHhConverterHour >=13 ) mealTimeCnt++;
  // if( stDt != endDt && stHhConverterHour<= 18 && endHhConverterHour >=19 ) mealTimeCnt++;
  // alert('diffDay :' + diffDay + 'diffHour:' +diffHour+ 'mealTimeCnt :' + mealTimeCnt+ 'endHhConverterHour :' + (dtConverterHour+endHhConverterHour)  +' stHhConverterHour :' + stHhConverterHour);
  // diffHour = diffHour - mealTimeCnt;
  //return diffHour;
};
