scwin.sbm_calAmt_submitdone = async function (e) {
  var row = ds_results.getRowPosition();
  // ds_calamt.setJSON(e.responseJSON.OUT_DS1);
  if (!ds_calamt.getRowCount() > 0) {
    await $c.gus.cfAlertMsg($p, row + 1 + "번 Row의 중기/작업도구 [" + ds_results.getCellData(row, "shortCd") + "]의해당 요율을 조회하는데 실패하였습니다.");
    ds_results.setCellData(row, "upr", 0);
    ds_results.setCellData(row, "sellAmt", 0);
    ds_results.setCellData(row, "calBtn", "1");
    return;
  }
  ;
  //원가계산 관련 메세지 처리
  if (ds_calamt.getCellData(0, "uprKnd") == 0) {
    // 해당 요율이 없습니다. -> 멈춤
    await $c.gus.cfAlertMsg($p, row + 1 + "번 Row의 중기/작업도구 [" + ds_results.getCellData(row, "shortCd") + "]의해당 요율을 조회하는데 실패하였습니다.");
    ds_results.setCellData(row, "upr", 0);
    ds_results.setCellData(row, "sellAmt", 0);
    ds_results.setCellData(row, "calBtn", "1");
    return;
  }
  if (ds_calamt.getCellData(0, "uprKnd") == 3 && ds_calamt.getCellData(0, "ctrtEndYn") == 1) {
    // 계약요율의 계약기간이 만료됨 -> 계속 진행
    await $c.gus.cfAlertMsg($p, row + 1 + "번 Row의 중기/작업도구 [" + ds_results.getCellData(row, "shortCd") + "]의 계약요율은 계약기간이 만료되었습니다.");
    return;
  }
  ds_results.setCellData(row, "upr", ds_calamt.getCellData(0, "upr"));
  ds_results.setCellData(row, "sellAmt", ds_calamt.getCellData(0, "amt"));
  ds_results.setCellData(row, "calBtn", "1");
};
