scwin.gr_results_onbeforeedit = async function (row, columnIndex, value) {};
scwin.gr_results_onafteredit = async function (row, columnIndex, value) {
  // 
  if (ds_results.getRowStatus(row) == 'C') {
    // gr_results.ColumnProp("shortCd", 'Edit') = "Any";   	   
    // gr_results.ColumnProp("hveqWrkImpleClsCd", 'Edit') = "Any";   
    gr_results.setCellReadOnly(row, 'shortCd', false);
    gr_results.setCellReadOnly(row, 'hveqWrkImpleClsCd', false);
  } else {
    // gr_results.ColumnProp("shortCd", 'Edit') = "None";   	   
    // gr_results.ColumnProp("hveqWrkImpleClsCd", 'Edit') = "None";   	
    gr_results.setCellReadOnly(row, 'shortCd', true);
    gr_results.setCellReadOnly(row, 'hveqWrkImpleClsCd', true);
  }
  if (ds_results.getCellData(row, "pchsAdjmStdCd") == "H") {
    //정산기준
    // gr_results.ColumnProp("sellAdptHhCnt", 'Edit') = "Any";  
    // gr_results.ColumnProp("sellAdptWt", 'Edit') = "None";  
    gr_results.setCellReadOnly(row, 'sellAdptHhCnt', false);
    gr_results.setCellReadOnly(row, 'sellAdptWt', true);
  } else {
    // gr_results.ColumnProp("sellAdptHhCnt", 'Edit') = "None";  
    // gr_results.ColumnProp("sellAdptWt", 'Edit') = "Any";  
    gr_results.setCellReadOnly(row, 'sellAdptHhCnt', true);
    gr_results.setCellReadOnly(row, 'sellAdptWt', false);
  }

  // OnCloseUp(row,colid)
  var colid = gr_results.getColumnID(columnIndex);
  if (colid == "hveqWrkImpleClsCd") {
    //중기작업도구구분
    ds_results.setCellData(row, "shortCd", ""); //작업도구번호
    ds_results.setCellData(row, "eqNm", ""); //작업도구명
    ds_results.setCellData(row, "eqCd", ""); //작업도구번호
    ds_results.setCellData(row, "kndCd", ""); //중기종류코드
    ds_results.setCellData(row, "nrmCd", ""); //중기규격코드
    ds_results.setCellData(row, "kndNm", ""); //중기종류명
    ds_results.setCellData(row, "lobranCd", ""); //점소코드  
  } else if (colid == "pchsAdjmStdCd") {
    //정산기준
    ds_results.setCellData(row, "sellAdptHhCnt", ""); //적용시간
    ds_results.setCellData(row, "sellAdptWt", ""); //적용중량
  }
  if (ds_results.getCellData(row, "hveqWrkImpleClsCd") == "H") {
    // gr_results.ColumnProp("pchsAdjmStdCd", 'Edit') = "Any";   
    gr_results.setCellReadOnly(row, 'pchsAdjmStdCd', false);
  } else {
    ds_results.setCellData(row, "pchsAdjmStdCd", "H");
    // gr_results.ColumnProp("pchsAdjmStdCd", 'Edit') = "None";   
    gr_results.setCellReadOnly(row, 'pchsAdjmStdCd', true);
  }

  // OnExit(row,colid,olddata)
  var colid = gr_results.getColumnID(columnIndex);
  if (colid == "shortCd" || colid == "sellClntNo" || colid == "sellLobranCd" || colid == "sellLobranNm" || colid == "bilgLobranCd" || colid == "bilgLobranNm") {
    var editData = ds_results.getCellData(row, colid);
    editData = editData.toUpperCase();
    ds_results.setCellData(row, colid, editData);

    // 인서트일때 왼쪽 데이터가 바뀌면 오른쪽 그리드에도 적용해야한다                                                                    
    if (value != ds_results.getCellData(row, colid)) {}
    if (colid == "shortCd") {
      ds_results.setCellData(row, "eqNm", ""); // 작업도구명
      ds_results.setCellData(row, "eqCd", ""); // 작업도구번호
      ds_results.setCellData(row, "kndCd", ""); // 중기종류코드
      ds_results.setCellData(row, "nrmCd", ""); // 중기규격코드
      ds_results.setCellData(row, "kndNm", ""); // 중기종류명
      ds_results.setCellData(row, "lobranCd", ""); // 점소코드   

      if (ds_results.getCellData(row, "hveqWrkImpleClsCd") == 'H') {
        scwin.f_openCommonPopUpGrid(1);
      } else if (ds_results.getCellData(row, "hveqWrkImpleClsCd") == 'I') {
        scwin.f_openCommonPopUpGrid(2);
      } else if (ds_results.getCellData(row, "hveqWrkImpleClsCd") == 'D') {
        scwin.f_openCommonPopUpGrid(6);
      }
    } else if (colid == "sellClntNo") {
      ds_results.setCellData(row, "sellClntNm", ""); //임대업체명
      scwin.f_openCommonPopUpGrid(3, 'F');
    } else if (colid == "sellClntNm") {
      ds_results.setCellData(row, "sellClntNo", ""); //임대업체
      scwin.f_openCommonPopUpGrid(3, 'F');
    } else if (colid == "sellLobranCd") {
      ds_results.setCellData(row, "sellLobranNm", ""); //매출부서명
      ds_results.setCellData(row, "bizDomCd", ""); //사업영역코드
      scwin.f_openCommonPopUpGrid(4);
    } else if (colid == "sellLobranNm") {
      ds_results.setCellData(row, "sellLobranCd", ""); //매출부서코드
      ds_results.setCellData(row, "bizDomCd", ""); //사업영역코드
      scwin.f_openCommonPopUpGrid(4);
    } else if (colid == "bilgLobranCd") {
      ds_results.setCellData(row, "bilgLobranNm", ""); //청구부서
      scwin.f_openCommonPopUpGrid(5);
    } else if (colid == "bilgLobranNm") {
      ds_results.setCellData(row, "bilgLobranCd", ""); //청구부서
      scwin.f_openCommonPopUpGrid(5);
    }
  } else if (colid == "stDt" || colid == "stHh" || colid == "endDt" || colid == "endHh") {
    var stDt = ds_results.getCellData(row, "stDt");
    var stHh = ds_results.getCellData(row, "stHh");
    var endDt = ds_results.getCellData(row, "endDt");
    var endHh = ds_results.getCellData(row, "endHh");
    var stDtm = stDt + stHh;
    var endDtm = endDt + endHh;
    if (ds_results.getCellData(row, "pchsAdjmStdCd")) {
      if (stDt != "" && stHh != "" && endDt != "" && endHh != "") {
        // $c.gus.cfValidateValue(stDt,"date=YYYYMMDD")
        var isDate = $c.date.isDate($p, stDt, false);
        if (!isDate) {
          await $c.win.alert($p, row + 1 + " 번째의 작업시작일자");
          // gr_results.ColSelect = "true";
          // gr_results.focus();
          // gr_results.SetColumn("stDt");
          gr_results.setFocusedCell(row, "stDt", true);
          return;
        }
        // $c.gus.cfValidateValue(stHh,"date=HHmm")
        isDate = $c.date.isDate($p, stHh, true);
        if (!isDate) {
          await $c.win.alert($p, row + 1 + " 번째의 작업시작시간");
          // gr_results.ColSelect = "true";
          // gr_results.focus();
          // gr_results.SetColumn("stHh");
          gr_results.setFocusedCell(row, "stHh", true);
          return;
        }
        // $c.gus.cfValidateValue(endDt,"date=YYYYMMDD")
        isDate = $c.date.isDate($p, endDt, false);
        if (!isDate) {
          await $c.win.alert($p, row + 1 + " 번째의 작업종료일자");
          // gr_results.ColSelect = "true";
          // gr_results.focus();
          // gr_results.SetColumn("endDt");
          gr_results.setFocusedCell(row, "endDt", true);
          return;
        }
        // $c.gus.cfValidateValue(endHh,"date=HHmm")
        isDate = $c.date.isDate($p, endHh, true);
        if (!isDate) {
          await $c.win.alert($p, row + 1 + " 번째의 작업종료시간");
          // gr_results.ColSelect = "true";
          // gr_results.focus();
          // gr_results.SetColumn("endHh");
          gr_results.setFocusedCell(row, "endHh", true);
          return;
        }
        if (stDtm > endDtm) {
          await $c.win.alert($p, row + 1 + " 번째의 작업시작일시는 작업종료일시 이전 이어야 합니다.");
          // gr_results.ColSelect = "true";
          // gr_results.focus();
          // gr_results.SetColumn("stDt");
          gr_results.setFocusedCell(row, "stDt", true);
          return;
        }
        //시간계산
        var diffHour = await scwin.f_diffHour(stDt, stHh, endDt, endHh);
        ds_results.setCellData(row, "sellAdptHhCnt", diffHour);
      }
    }
  }
};
